const item = $input.first() || { json: {} };
const raw = item.json || {};
const body = raw.body || raw;
const candidate_id = body.candidate_id ?? null;
return [{ json: { mode: candidate_id ? 'single' : 'batch', candidate_id: candidate_id ? String(candidate_id) : null } }];

const mode = $('Determine Mode').first().json.mode;
const resp = $input.first().json;
let rows = [];

if (mode === 'single') {
  rows = [resp];
} else {
  rows = resp.list || [];
}

const SINCE = '2025-11-01';

const hasText = (v) => v !== null && v !== undefined && String(v).trim().length > 0;
const hasNum = (v) => v !== null && v !== undefined && v !== '' && !Number.isNaN(Number(v));

function isGarbage(s) {
  const orig = (s || '').trim();
  const t = orig.toLowerCase();
  if (t.length === 0) return true;
  if (t.length === 1) return true;
  if (t.length === 2) {
    return !/^[A-Z]{2}$/.test(orig);
  }
  if (t.length > 80) return true;
  const noValues = new Set([
    'n/a','na','none','nil','null','tbd','test','-','--','...',
    '?','??','xx','xxx','abc','asdf','qwerty'
  ]);
  if (noValues.has(t)) return true;
  if (!/[aeiou]/.test(t)) return true;
  return false;
}

function detectLinkType(rawUrl) {
  const url = (rawUrl || '').trim();
  const u = url.toLowerCase();
  if (!u) return { type: 'icloud', url, original: url, file_id: null, note: 'empty link' };

  // Google Drive — rewrite to direct download URL with confirm=t to bypass virus-scan warning
  const gdriveFileMatch = url.match(/drive\.google\.com\/file\/d\/([a-zA-Z0-9_-]+)/);
  if (gdriveFileMatch) {
    return { type: 'pdf', url: 'https://drive.google.com/uc?export=download&confirm=t&id=' + gdriveFileMatch[1], original: url, file_id: null };
  }
  const gdriveIdMatch = url.match(/drive\.google\.com\/(?:open|uc)\?[^#]*[?&]id=([a-zA-Z0-9_-]+)/);
  if (gdriveIdMatch) {
    return { type: 'pdf', url: 'https://drive.google.com/uc?export=download&confirm=t&id=' + gdriveIdMatch[1], original: url, file_id: null };
  }
  if (/drive\.google\.com\//.test(u)) {
    return { type: 'pdf', url, original: url, file_id: null };
  }

  // Vercel Blob (public or private with presigned ?download=1)
  if (/\.public\.blob\.vercel-storage\.com\//.test(u) || /\.private\.blob\.vercel-storage\.com\//.test(u)) {
    return { type: 'pdf', url, original: url, file_id: null };
  }

  // LinkedIn
  if (/(?:^|\.|\/)linkedin\.com\//.test(u)) {
    return { type: 'linkedin', url, original: url, file_id: null };
  }

  // iCloud Drive (cannot scrape)
  if (/icloud\.com\/iclouddrive/.test(u)) {
    return { type: 'icloud', url, original: url, file_id: null };
  }

  // Anything ending in .pdf or with .pdf? in path → try as PDF
  if (/\.pdf(\?|$)/.test(u)) {
    return { type: 'pdf', url, original: url, file_id: null };
  }

  // Unknown: still try as PDF; if it's HTML the parser will fail gracefully
  return { type: 'pdf', url, original: url, file_id: null };
}

const keep = rows.filter(r => {
  if (!hasText(r['cv drive link'])) return false;
  if (mode !== 'single' && r.CreatedAt) {
    const created = String(r.CreatedAt).slice(0, 10);
    if (created < SINCE) return false;
  }
  if (isGarbage(r.position))   return false;
  if (isGarbage(r.department)) return false;
  if (mode !== 'single') {
    const fullyDone = hasText(r['extracted resume']) && hasNum(r['LLM score']) && Number(r['LLM score']) > 0;
    if (fullyDone) return false;
  }
  return true;
});

return keep.map(r => {
  const link = detectLinkType(r['cv drive link']);
  return {
    json: {
      candidate_id: String(r.Id ?? r.id),
      name: ((r['first name'] || '') + ' ' + (r['last name'] || '')).trim(),
      email: r.email || null,
      phone: r['phone number'] || null,
      department: r.department || null,
      position: r.position || null,
      cover_letter: r['cover letter'] || null,
      cv_drive_link: link.url,
      cv_drive_link_original: link.original,
      link_type: link.type,
      existing_extracted_resume: r['extracted resume'] || null
    }
  };
});

const ROLE_SUFFIXES = new Set([
  'engineer','developer','scientist','manager','specialist','analyst',
  'lead','senior','junior','principal','staff','associate',
  'intern','executive','admin','administrator','support',
  'technician','technologist','tester','designer',
  'owner','consultant','representative','rep','officer','assessor'
]);
const STOP = new Set(['the','a','an','of','and','or','in','for','to','with']);

function tokenize(s) {
  return (s || '').toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim().split(/\s+/)
    .filter(w => w.length >= 2)
    .filter(w => !STOP.has(w));
}
function domainTokens(s) {
  return new Set(tokenize(s).filter(w => !ROLE_SUFFIXES.has(w)));
}
function similarity(a, b) {
  const da = domainTokens(a);
  const db = domainTokens(b);
  if (da.size === 0 || db.size === 0) {
    const ta = new Set(tokenize(a));
    const tb = new Set(tokenize(b));
    if (ta.size === 0 || tb.size === 0) return 0;
    const c = [...ta].filter(w => tb.has(w)).length;
    return c / Math.max(ta.size, tb.size);
  }
  const c = [...da].filter(w => db.has(w)).length;
  return c / Math.max(da.size, db.size);
}

const candidate = $json;
const pos = (candidate.position || '').trim();

// Combine careers page JDs (12) + NocoDB JDs (Applied Scientist + others)
let combined = [];
try {
  const careers = ($('Fetch Careers JDs').first().json.list) || [];
  combined = combined.concat(careers);
} catch (e) {}
try {
  const noco = ($('List All JDs').first().json.list) || [];
  combined = combined.concat(noco.filter(j => (j.Position || '').trim().length > 0));
} catch (e) {}

// Try exact match first (case-insensitive)
const exact = combined.find(j => (j.Position || '').trim().toLowerCase() === pos.toLowerCase());
if (exact) {
  return { json: { ...candidate, jd_text: exact['Job Description'] || '', matched_position: exact.Position, match_source: 'exact', similarity: 1 } };
}

// Substring match — handles team/category prefixes/suffixes like 'Core Team - Senior Full Stack Engineer'
const normalize = (s) => (s || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
const posNorm = normalize(pos);
if (posNorm.length >= 4) {
  const substr = combined.find(j => {
    const jdNorm = normalize(j.Position);
    if (!jdNorm || jdNorm.length < 4) return false;
    return jdNorm.includes(posNorm) || posNorm.includes(jdNorm);
  });
  if (substr) {
    return { json: { ...candidate, jd_text: substr['Job Description'] || '', matched_position: substr.Position, match_source: 'substring', similarity: 0.9 } };
  }
}

// Fuzzy match
const FUZZY_THRESHOLD = 0.5;
const scored = combined.map(j => ({ jd: j, sim: similarity(pos, j.Position) })).sort((a, b) => b.sim - a.sim);
const best = scored[0];
if (best && best.sim >= FUZZY_THRESHOLD) {
  return { json: { ...candidate, jd_text: best.jd['Job Description'] || '', matched_position: best.jd.Position, match_source: 'fuzzy', similarity: best.sim } };
}

// No match — set null so the downstream gate can skip scoring
return { json: { ...candidate, jd_text: null, matched_position: null, match_source: 'none', similarity: 0 } };

// Best-effort LinkedIn HTML → resume-like text. Never throws.
const c = $('Find Best JD Match').item.json;
const raw = $json;
let html = '';
if (typeof raw === 'string') html = raw;
else if (raw && typeof raw.data === 'string') html = raw.data;
else if (raw && typeof raw.body === 'string') html = raw.body;
else if (raw) html = JSON.stringify(raw);

const origUrl = c.cv_drive_link_original || c.cv_drive_link || '';
let text;

if (!html || !html.trim() || html.trim().length < 200) {
  text = '[LINKEDIN PROFILE — could not retrieve page content (likely blocked or auth-walled). Profile URL: ' + origUrl + '. Treat as resume content unavailable; output minimal placeholder JSON.]';
} else {
  const decode = (s) => (s || '').replace(/&amp;/g,'&').replace(/&quot;/g,'"').replace(/&#x27;/g,"'").replace(/&#39;/g,"'").replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&nbsp;/g,' ');
  const og = (re) => { const m = html.match(re); return m ? decode(m[1]) : ''; };
  const ogTitle = og(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']*)["']/i);
  const ogDesc  = og(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']*)["']/i);
  const metaDesc = og(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']*)["']/i);
  const titleTag = og(/<title[^>]*>([\s\S]*?)<\/title>/i);

  const stripped = html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<[^>]+>/g, ' ');
  const cleaned = decode(stripped).replace(/\s+/g, ' ').trim().slice(0, 8000);

  text = '[LINKEDIN PROFILE — best-effort extraction; LinkedIn auth wall may have hidden parts of the profile]\nProfile URL: ' + origUrl + '\n\nPage title: ' + (titleTag || ogTitle) + '\nHeadline / og:title: ' + ogTitle + '\nog:description: ' + ogDesc + '\nmeta description: ' + metaDesc + '\n\n--- Visible page text (truncated) ---\n' + cleaned;
}
return { json: { text } };

const c = $('Find Best JD Match').item.json;
const origUrl = c.cv_drive_link_original || c.cv_drive_link || '';
const text = '[ICLOUD DRIVE LINK — cannot extract content programmatically. iCloud Drive sharing pages require CloudKit authentication tokens that are not accessible to this workflow. Recruiter to manually review. URL: ' + origUrl + '. Treat as resume content unavailable; output minimal placeholder JSON.]';
return { json: { text } };

// ROBUST: never throw — pass placeholder text if no extractable content
const text = ($json && $json.text) ? String($json.text) : '';
const c = $('Find Best JD Match').item.json;
let resumeText, src_status;
if (!text.trim()) {
  resumeText = '[NO RESUME TEXT — extraction step produced no content. Link type: ' + (c.link_type || 'unknown') + '. Treat as resume content unavailable; output minimal placeholder JSON.]';
  src_status = 'empty';
} else {
  resumeText = text.length > 30000 ? text.slice(0, 30000) + '\n\n[...truncated]' : text;
  src_status = 'ok';
}
let jdText = c.jd_text || '';
if (!jdText) {
  try { jdText = $('Parse Generated JD').item.json.jd_text || ''; } catch (e) {}
}
return { json: {
  candidate_id: c.candidate_id,
  position: c.position,
  cover_letter: c.cover_letter || '',
  link_type: c.link_type || null,
  jd_text: jdText,
  resume_text: resumeText,
  src_status: src_status
} };

