// ROBUST: never throw — always return a valid extracted_resume_obj so Save Extracted Resume body is valid JSON
const resp = $json;
const prep = $('Prepare Resume Text').item.json;
const raw = resp && resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;

let parsed;
let extraction_error = null;

if (!raw) {
  parsed = { error: 'No content from GPT Extract Resume', name: null, email: null, contact: null, total_experience_years: null, skills: [], previous_jobs: [], education: [], certifications: [], summary: 'Resume could not be extracted.' };
  extraction_error = 'no_content';
} else {
  let text = String(raw).trim();
  const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) text = fence[1].trim();
  try {
    parsed = JSON.parse(text);
    if (!parsed || typeof parsed !== 'object') {
      parsed = { error: 'Parsed value not an object', raw_excerpt: text.slice(0, 500), name: null, email: null, skills: [], previous_jobs: [], education: [], summary: 'Resume parse returned non-object.' };
      extraction_error = 'not_object';
    }
  } catch (e) {
    parsed = { error: 'Non-JSON response from GPT', raw_excerpt: text.slice(0, 500), name: null, email: null, skills: [], previous_jobs: [], education: [], summary: 'Resume parse failed.' };
    extraction_error = 'non_json';
  }
}

// Annotate source
parsed.source_link_type = prep.link_type || null;
parsed.source_status = prep.src_status || null;

return { json: {
  candidate_id: prep.candidate_id,
  position: prep.position,
  cover_letter: prep.cover_letter || '',
  jd_text: prep.jd_text || '',
  extracted_resume_obj: parsed,
  extracted_resume_str: JSON.stringify(parsed, null, 2),
  extraction_error: extraction_error
} };

// ROBUST: never throw — default to score=0 with diagnostic reason on failure
const resp = $json;
const c = $('Has JD Match?').item.json;
const raw = resp && resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content;
let score = 0;
let reason = 'Scoring failed: no content from GPT Score.';

if (raw) {
  let text = String(raw).trim();
  const fence = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) text = fence[1].trim();
  try {
    const parsed = JSON.parse(text);
    score = Math.max(0, Math.min(100, Math.round(Number(parsed.score) || 0)));
    reason = String(parsed.reason || '').trim() || 'No reason provided by scorer.';
  } catch (e) {
    score = 0;
    reason = 'Scoring failed: GPT returned non-JSON. Excerpt: ' + text.slice(0, 300);
  }
}

return { json: { candidate_id: c.candidate_id, LLM_score: score, reason } };

