// Scrape 5C Network careers page using n8n http helper (works on all Node versions).
const ua = 'Mozilla/5.0';
const helpers = this.helpers;

async function fetchHtml(url) {
  try {
    return await helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': ua }
    });
  } catch (e) {
    return '';
  }
}

const careersHtml = await fetchHtml('https://www.5cnetwork.com/careers');
if (!careersHtml) return [{ json: { list: [] } }];

const ldRe = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
const ldMatches = careersHtml.match(ldRe) || [];
let jobUrls = [];
for (const m of ldMatches) {
  const jsonStr = m.replace(/<script[^>]*>|<\/script>/g, '');
  try {
    const parsed = JSON.parse(jsonStr);
    if (parsed['@type'] === 'ItemList' && Array.isArray(parsed.itemListElement) && parsed.itemListElement.length > 0) {
      jobUrls = parsed.itemListElement.map(it => (it.item || it).url).filter(Boolean);
      break;
    }
  } catch (e) {}
}

const jobs = await Promise.all(jobUrls.map(async (url) => {
  const html = await fetchHtml(url);
  if (!html) return null;
  const matches = html.match(/<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi) || [];
  for (const m of matches) {
    const jsonStr = m.replace(/<script[^>]*>|<\/script>/g, '');
    try {
      const parsed = JSON.parse(jsonStr);
      if (parsed['@type'] === 'JobPosting') {
        const desc = String(parsed.description || '')
          .replace(/<[^>]+>/g, ' ')
          .replace(/&nbsp;/g, ' ')
          .replace(/&amp;/g, '&')
          .replace(/&quot;/g, '"')
          .replace(/&#39;/g, "'")
          .replace(/\s+/g, ' ')
          .trim();
        return { Position: parsed.title || '', 'Job Description': desc };
      }
    } catch (e) {}
  }
  return null;
}));

return [{ json: { list: jobs.filter(Boolean) } }];

// Use existing extracted resume — skip PDF/GPT extraction.
// Read from $json so we get the upstream candidate data (whether it came via FALSE-branch
// of IF No JD Match or via the generate path through Restore Candidate Data).
const c = $json;
let parsed;
try {
  parsed = JSON.parse(c.existing_extracted_resume);
  if (!parsed || typeof parsed !== 'object') {
    parsed = { error: 'invalid_existing', summary: 'Existing extracted resume parsed but not an object.' };
  }
} catch (e) {
  parsed = { error: 'parse_failed', summary: 'Could not parse existing extracted resume JSON.' };
}
return { json: {
  candidate_id: c.candidate_id,
  position: c.position,
  cover_letter: c.cover_letter || '',
  jd_text: c.jd_text || '',
  matched_position: c.matched_position || '',
  match_source: c.match_source || '',
  extracted_resume_obj: parsed,
  extracted_resume_str: JSON.stringify(parsed, null, 2),
  extraction_error: null,
  used_existing: true
}};

// Save Extracted Resume returns NocoDB's PATCH response.
// We want Parse Extraction's data to keep flowing downstream so GPT Score has it.
return $('Parse Extraction').item;

// Dedup careers JDs vs existing NocoDB list. Emit one item per NEW JD.
const careers = (($input.first() && $input.first().json && $input.first().json.list) || []);
const existing = (($('List All JDs').first() && $('List All JDs').first().json && $('List All JDs').first().json.list) || []);
const have = new Set(existing.map(j => (j.Position || '').trim().toLowerCase()).filter(Boolean));
const newOnes = careers.filter(jd => {
  const title = (jd.Position || '').trim();
  return title && !have.has(title.toLowerCase());
});
return newOnes.map(jd => ({
  json: {
    Position: (jd.Position || '').trim(),
    'Job Description': jd['Job Description'] || ''
  }
}));

